choose.when:
AND (

    (u.dept_id = #{did} OR u.dept_id IN (SELECT dept_id FROM sys_dept WHERE find_in_set(#{did}, ancestors) > 0))

)

mapper.select:
select report_id from pm_daily_report
where user_id = #{userId} and report_date = #{reportDate}
limit 1

mapper.update:
update pm_daily_report
report_date = #{reportDate}, user_id = #{userId}, dept_id = #{deptId}, total_work_hours = #{totalWorkHours}, del_flag = #{delFlag}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where report_id = #{reportId}

mapper.select:
SELECT r.report_date AS reportDate, COUNT(DISTINCT r.user_id) AS submittedCount FROM pm_daily_report r INNER JOIN sys_user u ON r.user_id = u.user_id LEFT JOIN sys_dept d ON u.dept_id = d.dept_id
r.del_flag = '0' AND u.del_flag = '0' AND u.status = '0' AND u.user_id != 1 AND u.user_id NOT IN (SELECT user_id FROM pm_daily_report_whitelist WHERE del_flag = '0') AND r.report_date BETWEEN #{startDate} AND #{endDate}
AND r.user_id IN ( SELECT DISTINCT pm.user_id FROM pm_project_member pm INNER JOIN pm_project p_pn ON pm.project_id = p_pn.project_id WHERE pm.is_active = '1' AND pm.del_flag = '0' AND p_pn.del_flag = '0' AND p_pn.project_name LIKE CONCAT('%', #{projectName}, '%') )
${params.dataScope}
GROUP BY r.report_date

SELECT u.user_id AS userId, u.nick_name COLLATE utf8mb4_unicode_ci AS nickName, d.dept_name AS deptName, GROUP_CONCAT(DISTINCT p.project_name ORDER BY p.project_name SEPARATOR '、') AS projectNames, r.total_work_hours AS totalWorkHours, LEFT(GROUP_CONCAT( dd.work_content ORDER BY dd.detail_id SEPARATOR '；' ), 50) AS workContentSummary FROM pm_daily_report r INNER JOIN sys_user u ON r.user_id = u.user_id LEFT JOIN sys_dept d ON u.dept_id = d.dept_id LEFT JOIN pm_daily_report_detail dd ON dd.report_id = r.report_id AND dd.entry_type = 'work' AND dd.del_flag = '0' LEFT JOIN pm_project p ON dd.project_id = p.project_id AND p.del_flag = '0'
r.del_flag = '0' AND u.del_flag = '0' AND u.status = '0' AND r.report_date = #{reportDate}
AND r.user_id IN ( SELECT DISTINCT pm.user_id FROM pm_project_member pm INNER JOIN pm_project p_pn ON pm.project_id = p_pn.project_id WHERE pm.is_active = '1' AND pm.del_flag = '0' AND p_pn.del_flag = '0' AND p_pn.project_name LIKE CONCAT('%', #{projectName}, '%') )
${params.dataScope}
GROUP BY r.report_id, u.user_id, u.nick_name, d.dept_name, r.total_work_hours ORDER BY d.dept_name, u.nick_name COLLATE utf8mb4_unicode_ci

SELECT p.project_id AS projectId, p.project_name AS projectName, p.estimated_workload AS estimatedWorkload, ROUND(p.actual_workload / 8, 3) + COALESCE(p.adjust_workload, 0) AS actualPersonDays, EXISTS( SELECT 1 FROM pm_project_contract_rel pcr WHERE pcr.project_id = p.project_id AND pcr.del_flag = '0' ) AS hasContract, u.user_id AS userId, u.nick_name COLLATE utf8mb4_unicode_ci AS nickName, d.dept_name COLLATE utf8mb4_unicode_ci AS deptName, r.report_date AS reportDate, r.total_work_hours AS totalWorkHours FROM pm_project p INNER JOIN pm_project_member m ON m.project_id = p.project_id AND m.is_active = '1' AND m.del_flag = '0' INNER JOIN sys_user u ON u.user_id = m.user_id INNER JOIN sys_dept d ON d.dept_id = u.dept_id LEFT JOIN pm_daily_report r ON r.user_id = m.user_id AND DATE_FORMAT(r.report_date, '%Y-%m') = #{yearMonth} AND r.del_flag = '0'
p.del_flag = '0'
AND (p.project_dept = #{deptId} OR p.project_dept IN ( SELECT dept_id FROM sys_dept WHERE FIND_IN_SET(#{deptId}, ancestors) > 0 ))
AND p.project_id = #{projectId}
${params.dataScope}
ORDER BY p.project_id, u.user_id, r.report_date
